import streamlit as stfrom streamlit_gsheets import GSheetsConnectionimport pandas as pdfrom datetime import datetimeimport urllib.parse# --- SAYFA AYARLARI ---st.set_page_config(page_title="Bostanlı Çözüm Bulut Paneli", layout="wide")# --- GOOGLE SHEETS BAĞLANTISI ---# Tablo linkinizi buraya tanımlıyoruzURL = "https://docs.google.com/spreadsheets/d/18BUCCdmATfgHJB1JkM9-T5lhoUaSXes55iMgHVRpOP4/edit?usp=sharing"conn = st.connection("gsheets", type=GSheetsConnection)# --- WHATSAPP FONKSİYONU ---def whatsapp_link_olustur(tel, mesaj):    tel_str = str(tel).replace(" ", "").replace("-", "")    if tel_str.startswith("0"): tel_str = "90" + tel_str[1:]    elif not tel_str.startswith("90"): tel_str = "90" + tel_str    encoded_mesaj = urllib.parse.quote(mesaj)    return f"https://wa.me/{tel_str}?text={encoded_mesaj}"# --- ARAYÜZ ---st.sidebar.title("☁️ Bulut Yönetim")sayfa = st.sidebar.radio("İşlem Seçiniz:", ["Veli Görüşmeleri", "Kasa İşlemleri", "Kurucu Raporu"])if sayfa == "Veli Görüşmeleri":    st.header("📞 Veli Görüşme Kayıt")        # Mevcut verileri oku (Tabloyu görmek için)    existing_data = conn.read(spreadsheet=URL, worksheet="gorusmeler")        with st.form("veli_formu"):        v_ad = st.text_input("Veli / Öğrenci Ad Soyad")        v_tel = st.text_input("Telefon Numarası")        v_konu = st.selectbox("Konu", ["Yeni Kayıt", "Taksit", "Rehberlik", "Diğer"])        v_durum = st.selectbox("Durum", ["Beklemede", "Olumlu", "Kayıt Tamamlandı"])        v_not = st.text_area("Detaylar")        submit = st.form_submit_button("Kaydet ve Google Sheets'e Gönder")            if submit:        # Yeni satırı hazırla        new_row = pd.DataFrame([{            "Tarih": datetime.now().strftime("%Y-%m-%d %H:%M"),            "Ad Soyad": v_ad,            "Telefon": v_tel,            "Konu": v_konu,            "Durum": v_durum,            "Notlar": v_not        }])                # Mevcut veriye ekle ve geri yükle        updated_df = pd.concat([existing_data, new_row], ignore_index=True)        conn.update(spreadsheet=URL, worksheet="gorusmeler", data=updated_df)                st.success("✅ Veri başarıyla Google Sheets'e işlendi!")        wa_link = whatsapp_link_olustur(v_tel, f"Merhaba {v_ad}, görüşmemiz için teşekkürler.")        st.markdown(f'<a href="{wa_link}" target="_blank"><button style="background-color:#25D366;color:white;border:none;padding:10px;border-radius:5px;cursor:pointer;">WhatsApp Mesajı At</button></a>', unsafe_allow_html=True)# Kasa ve Rapor sayfaları da aynı mantıkla (conn.read ve conn.update) çalışacak.